module binary_adder_4bit (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire cin,
    output wire [3:0] sum,
    output wire cout
);

    wire [4:0] sum_overflow;

    assign sum_overflow = a + b + cin;
    assign sum = sum_overflow[3:0];
    assign cout = sum_overflow[4];

endmodule
